  await s('create.lists', async () => {
    await db.query(`CREATE TABLE IF NOT EXISTS lists (
      id           serial PRIMARY KEY,
      workspace_id int NOT NULL REFERENCES workspaces(id) ON DELETE CASCADE,
      name         text NOT NULL,
      type         text NOT NULL CHECK (type IN ('contacts','companies')),
      description  text,
      created_at   timestamptz DEFAULT now()
    )`);
    await db.query(`CREATE INDEX IF NOT EXISTS idx_lists_ws ON lists(workspace_id)`);
  });

  await s('create.list_contacts', async () => {
    await db.query(`CREATE TABLE IF NOT EXISTS list_contacts (
      list_id    int NOT NULL REFERENCES lists(id) ON DELETE CASCADE,
      contact_id int NOT NULL REFERENCES contacts(id) ON DELETE CASCADE,
      added_at   timestamptz DEFAULT now(),
      PRIMARY KEY (list_id, contact_id)
    )`);
  });

  await s('create.list_companies', async () => {
    await db.query(`CREATE TABLE IF NOT EXISTS list_companies (
      id                  serial PRIMARY KEY,
      list_id             int NOT NULL REFERENCES lists(id) ON DELETE CASCADE,
      workspace_id        int NOT NULL,
      company_name        text NOT NULL DEFAULT '',
      li_company_url      text NOT NULL DEFAULT '',
      company_linkedin_id text,
      created_at          timestamptz DEFAULT now()
    )`);
    await db.query(`CREATE INDEX IF NOT EXISTS idx_lco_list ON list_companies(list_id)`);
    await db.query(`CREATE INDEX IF NOT EXISTS idx_lco_ws   ON list_companies(workspace_id)`);
  });

